      { step: '04', title: 'в•ЁГ№в•Ёв–‘в•Ёв–“в•Ёв•Ўв•ӨГҮв•ӨГӘв•Ёв•Ўв•Ёв•ңв•Ёв••в•Ёв•Ў', desc: 'в•ЁВЎв•Ёв•ңв•Ёв”Өв•Ёв•ӣв•ӨГјв•Ёв•‘в•Ёв•ӣв•Ёв”җ в•Ёв••в•Ёв•–в•Ёв–“в•Ёв•—в•Ёв•Ўв•Ёв•‘в•Ёв–‘в•Ёв•Ўв•ӨГ©в•ӨГјв•ӨГ…. в•ЁГЎв•Ёв•Ўв•Ёв•–в•ӨГўв•Ёв•—в•ӨГ®в•ӨГ©в•Ёв–‘в•ӨГ©в•ӨГҜ в•Ёв•ӣв•Ёв–’в•ӨГјв•ӨГўв•Ёв•ўв•Ёв”Өв•Ёв–‘в•ӨГ„в•ӨГ©в•ӨГјв•ӨГ… в•Ёв•ңв•Ёв•Ўв•Ёв•қв•Ёв•Ўв•Ёв”Өв•Ёв•—в•Ёв•Ўв•Ёв•ңв•Ёв•ңв•Ёв•ӣ. в•ЁЖ’в•Ёв–‘в•ӨГҘв•Ёв••в•Ёв•Ўв•Ёв•ңв•ӨГ© в•Ёв•қв•Ёв•ӣв•Ёв•ўв•Ёв•Ўв•ӨГ© в•Ёв•ӣв•Ёв”Өв•Ёв•Ўв•ӨГ©в•ӨГ®в•ӨГјв•ӨГ… в•Ёв•• в•ӨГјв•ӨГҮв•Ёв–‘в•Ёв•–в•ӨГў в•ӨГўв•Ёв•Јв•ӨГ©в•Ёв••.' }
